// Check if this is an auto-refresh trigger
const isAutoRefresh = msg.topic === 'timer-refresh';

if (isAutoRefresh) {
    node.warn('Auto-refresh initiated by timer');
}

// Check if token is still valid
const now = Math.floor(Date.now() / 1000);
if (tokenData.accessToken && tokenData.expiresAt && now < tokenData.expiresAt - 60 && !isAutoRefresh) {
    // Token still valid (with 60s buffer) and not auto-refresh
    const expiresIn = tokenData.expiresAt - now;
    const minutes = Math.floor(expiresIn / 60);
    const seconds = expiresIn % 60;
    node.status({
        fill: "green",
        shape: "dot",
        text: `Token valid: ${minutes}m ${seconds}s remaining`
    });

    node.warn(`Reusing existing token (expires in ${minutes}m ${seconds}s)`);

    // Return existing valid token without making new request
    msg.payload = {
        accessToken: tokenData.accessToken,
        refreshToken: tokenData.refreshToken,
        expiresAt: tokenData.expiresAt,
        expiresIn: expiresIn,
        valid: true,
        reused: true
    };
    return [null, msg]; // Send to output 2 (skip HTTP request)
}

// Token expired or doesn't exist or auto-refresh triggered, request new one
node.status({fill: "yellow", shape: "ring", text: "Requesting new token..."});
node.warn('Requesting new access token from IED');

msg.url = `https://${config.ip}/device/edge/api/v2/login/direct`;
msg.method = "POST";
msg.headers = {
    "Content-Type": "application/json"
};
msg.payload = {
    username: config.username,
    password: config.password
};

// Store node reference for status update
flow.set('tokenManagerNode', node);

return [msg, null]; // Send to output 1 (HTTP request)

const tokenData = msg.payload;
const tokenManagerNode = flow.get('tokenManagerNode');

if (tokenData && tokenData.accessToken) {
    // Override expiresAt for testing (2 minutes from now)
    const now = Math.floor(Date.now() / 1000);
    //tokenData.expiresAt = now + 120; // Test: Token expires in 2 minutes

    // Store token data in GLOBAL context with modified expiry
    global.set('iedAccessToken', tokenData);

    // Calculate time until expiry
    const expiresIn = tokenData.expiresAt - now;
    const minutes = Math.floor(expiresIn / 60);
    const seconds = expiresIn % 60;

    // Update both node statuses
    node.status({
        fill: "green",
        shape: "dot",
        text: `Token active: ${minutes}m ${seconds}s`
    });

    // Update Token Manager node status
    if (tokenManagerNode) {
        tokenManagerNode.status({
            fill: "green",
            shape: "dot",
            text: `Token valid: ${minutes}m ${seconds}s remaining`
        });
    }

    // Cancel existing timer if any
    const existingTimer = flow.get('tokenRefreshTimer');
    if (existingTimer) {
        clearTimeout(existingTimer);
        node.warn('Cleared previous refresh timer');
    }

    // Schedule refresh 60 seconds before expiry
    const refreshDelay = Math.max((expiresIn - 60) * 1000, 5000);
    const refreshInSeconds = Math.floor(refreshDelay / 1000);

    node.warn(`Token received successfully`);
    node.warn(`Token expires at: ${new Date(tokenData.expiresAt * 1000).toLocaleTimeString()}`);
    node.warn(`Auto-refresh scheduled in ${refreshInSeconds} seconds`);

    // Store current node instance for callback
    const currentNode = node;

    // Create new timer that triggers via global flag
    const newTimer = setTimeout(() => {
        const triggerTime = new Date().toLocaleTimeString();
        currentNode.warn(`â° Timer fired at ${triggerTime} - setting refresh trigger`);

        // Set global trigger flag
        global.set('tokenRefreshTrigger', {
            timestamp: Date.now(),
            triggered: true
        });

        currentNode.status({
            fill: "yellow",
            shape: "ring",
            text: "Refresh pending..."
        });
    }, refreshDelay);

    // Store timer reference
    flow.set('tokenRefreshTimer', newTimer);

    msg.payload = {
        accessToken: tokenData.accessToken,
        refreshToken: tokenData.refreshToken,
        expiresAt: tokenData.expiresAt,
        expiresIn: expiresIn,
        valid: true,
        newToken: true,
        nextRefreshIn: refreshInSeconds
    };

    return [msg, null];
} else {
    const errorMsg = 'Failed to retrieve access token from IED';
    node.status({fill: "red", shape: "ring", text: "Token request failed"});
    node.error(errorMsg);

    if (tokenManagerNode) {
        tokenManagerNode.status({fill: "red", shape: "ring", text: "Request failed"});
    }

    msg.payload = { 
        valid: false, 
        error: "Failed to get token",
        response: tokenData
    };
    return [msg, null];
}

// Check if refresh was triggered
const trigger = global.get('tokenRefreshTrigger');

if (trigger && trigger.triggered) {
    const triggerTime = new Date(trigger.timestamp).toLocaleTimeString();
    node.warn(`Refresh trigger detected (set at ${triggerTime})`);

    // Clear the flag
    global.set('tokenRefreshTrigger', {triggered: false});

    // Send message to trigger token refresh
    msg.topic = 'timer-refresh';
    msg.payload = 'auto-refresh';

    node.status({fill: "green", shape: "dot", text: "Triggering refresh"});

    return msg;
}

